%%%%%%%%%% Function fMedianLineV01.m %%%%%%%%%%% Kei Nakamura% Created on Saturday, July 26th 2008.% Modified on %% function out = fMedianLineV01(in,wid)% median fileterfunction out = fmedianLineV01(in,wid,rank)numPx = numel(in);      % number of pixelfrc = mod(numPx,wid);   % get dfractionnumSc = (numPx-frc)/wid;    % number of sectionindP = 1+frc;           % index of pixelfor ii=1:numSc    prt = in(indP:indP+wid-1);      % part of array        [num, ind] = sort(prt);  % find max    vl = sum(num(1:end-rank))/(wid-rank);    % value to be replaced    rpl = zeros(rank,1)+vl;                 % replacement array    prt(ind(end-rank+1:end)) = rpl;         % replacing        in(indP:indP+wid-1) = prt;        indP = indP + wid;    endout = in;
